import { isBridgedApiKey, isValidBridgedOrgId, resolveBridgedAuth } from '../src/auth-credentials';
import { BridgedHttpClient } from '../src/bridgedai-client';

const VALID_KEY =
  'brdg_test_sk_ak_29c12f28-7c0e-4767-8d31-fd9034b1fc49_X48oopZgESSfNLNqEsIj-dlFvyHOaKWabdsKpa4u';

describe('auth-credentials', () => {
  it('detects brdg_* org API keys with strict backend-aligned format', () => {
    expect(isBridgedApiKey(VALID_KEY)).toBe(true);
    expect(isBridgedApiKey('brdg_test_sk_kid_short')).toBe(false);
    expect(isBridgedApiKey('eyJhbGciOiJIUzI1NiJ9.x')).toBe(false);
  });

  it('validates org id format', () => {
    expect(isValidBridgedOrgId('org_29c12f28-7c0e-4767-8d31-fd9034b1fc49')).toBe(true);
    expect(isValidBridgedOrgId('org_invalid')).toBe(false);
  });

  it('routes mislabeled access-token to apiKey', () => {
    expect(resolveBridgedAuth({ accessToken: VALID_KEY })).toEqual({ apiKey: VALID_KEY });
  });

  it('BridgedHttpClient never sends Bearer for brdg_* accessToken', () => {
    const client = new BridgedHttpClient({
      baseUrl: 'https://api.test',
      orgId: 'org_29c12f28-7c0e-4767-8d31-fd9034b1fc49',
      accessToken: VALID_KEY,
    });
    const headers = (client as unknown as { authHeaders(): Record<string, string> }).authHeaders();
    expect(headers['x-api-key']).toBe(VALID_KEY);
    expect(headers.authorization).toBeUndefined();
  });
});
